import React from 'react';

const TestButton = () => {
  const handleClick = () => {
    console.log('Test button clicked!');
    alert('Test button is working!');
  };

  return (
    <div style={{ padding: '20px', background: '#f0f0f0', margin: '10px', borderRadius: '8px' }}>
      <h3>Button Test Component</h3>
      <button 
        onClick={handleClick}
        style={{
          background: '#007bff',
          color: 'white',
          border: 'none',
          padding: '10px 20px',
          borderRadius: '5px',
          cursor: 'pointer',
          fontSize: '14px'
        }}
      >
        Click Me to Test
      </button>
      <p style={{ fontSize: '12px', color: '#666', marginTop: '10px' }}>
        If this button works, React event handlers are functioning properly.
      </p>
    </div>
  );
};

export default TestButton;
